#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

int n,m,w[N],v[N],l[N],r[N];
long long s,sum[N][2];

long long calc(int num){
    for(int i=1;i<=n;i++){
        sum[i][0]=sum[i-1][0];
        sum[i][1]=sum[i-1][1];
        if(w[i]>=num)
            sum[i][0]++,sum[i][1]+=v[i];
    }
    long long res=0;
    for(int i=1;i<=m;i++)
        res+=(sum[r[i]][0]-sum[l[i]-1][0])*(sum[r[i]][1]-sum[l[i]-1][1]);
    return res;
}

long long cabs(long long x){
    return max(x,-x);
}

int main(){
    scanf("%d%d%lld",&n,&m,&s);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&w[i],&v[i]);
    for(int i=1;i<=m;i++)
        scanf("%d%d",&l[i],&r[i]);
    int l=1,r=1e6;
    while(l<r){
        int mid=l+r>>1;
        if(calc(mid)<=s)
            r=mid;
        else
            l=mid+1;
    }
    printf("%lld",min(cabs(s-calc(l)),cabs(calc(l-1)-s)));
    return 0;
}
